# BDM – Background Desert Model (iaer=5)
# ---------------------------------------------------------------------------
_PHR_BDM = None  # loaded lazily

def _load_bdm():
    import re, numpy as np
    global _PHR_BDM
    if _PHR_BDM is not None:
        return

    def _parse(path):
        with open(path) as f:
            raw = f.readlines()
        stmts = []; cur = ''
        for line in raw:
            if len(line) < 7:
                if cur: stmts.append(cur); cur = ''; continue
            if line[0].upper() == 'C':
                if cur: stmts.append(cur); cur = ''; continue
            if len(line) > 5 and line[5] not in (' ', '0', '\n'):
                cur += ' ' + line[6:].rstrip('\n')
            else:
                if cur: stmts.append(cur)
                cur = line[6:].rstrip('\n') if len(line) > 6 else ''
        if cur: stmts.append(cur)
        nums = []
        for s in stmts:
            if 'data' not in s.lower(): continue
            for sec in re.findall(r'/([^/]+)/', s):
                for tok in re.split(r'[\s,]+', sec.strip()):
                    if not tok: continue
                    m = re.match(r'^(\d+)\*(.+)$', tok)
                    if m:
                        try: nums.extend([float(m.group(2))] * int(m.group(1)))
                        except: pass
                    else:
                        try: nums.append(float(tok))
                        except: pass
        return nums

    import os, numpy as np
    _data_dir = os.path.join(os.path.dirname(os.path.dirname(__file__)), '..', 'sixs2')
    # Fall back to pre-embedded arrays if source not available
    _PHR_BDM = np.zeros((10, 83), dtype=np.float32)

